398	/**
399	 * The presence requirement one `requiredWhenEquals` rule imposes: when the
400	 * `when` field's value is one of `equals`, the `target` field is required, and
401	 * an absent-OR-empty target emits `message` at the target's path. Mirrors the
402	 * `method`-gated email/phone requirement of `contact.tsx:91-109`.
403	 *
404	 * The "required" sense here is PRESENCE-and-non-emptiness, not mere
405	 * key-presence. The oracle gates `email` as `Schema.optional(Email)` where
406	 * `Email` enforces `isMinLength(1)`, so `{ method: 'email', email: '' }` is a
407	 * decode error, not a success: a visibly-blank required field must never be
408	 * representable as valid (`make-impossible-states-unrepresentable`). The
409	 * recommended modelling pairs this rule with an `optional: true` `email`/text
410	 * target (optional-at-key, non-empty-when-present), where the FIELD codec
411	 * already rejects a present `''` (and does so BEFORE this struct-level filter
412	 * runs, so no duplicate issue is reported); this predicate additionally rejects
413	 * the absent/empty target so the requirement holds even if a definition gates
414	 * an empty-permitting `optionalText` target.
415	 */
416	const rulePresenceIssue = (
417	  rule: CrossFieldRule,
418	  value: Record<string, unknown>,
419	): PresenceIssue | undefined => {
420	  const trigger = value[rule.when];
421	  const triggered =
422	    typeof trigger === 'string' && rule.equals.includes(trigger as never);
423	  const target = value[rule.target];
424	  const unsatisfied = target === undefined || target === '';
425	  return triggered && unsatisfied
426	    ? { path: [rule.target], issue: rule.message }
427	    : undefined;
428	};
