430	/**
431	 * The SINGLE struct-level presence filter for a definition: the variant's
432	 * selected-branch requirements plus every cross-field rule, accumulated into one
433	 * issue list. Composing one accumulating filter (rather than chaining a
434	 * `.check` per concern) matches the oracle's single struct-level
435	 * `Schema.makeFilter` and is REQUIRED for fidelity — chained `.check`s ABORT
436	 * after the first failing filter (Effect's default), so two unsatisfied rules
437	 * (the contact/volunteer `email`+`phone` pair) would surface only one. One
438	 * filter collecting all issues reproduces the oracle's "report multiple failures
439	 * at once" behaviour without depending on a non-default `errors: 'all'` decode.
440	 */
441	const makePresenceFilter = (definition: FormDefinition) =>
442	  Schema.makeFilter(
443	    (value: Record<string, unknown>) => {
444	      const issues: Array<PresenceIssue> = [];
445	      if (definition.variant) {
446	        issues.push(...variantPresenceIssues(definition.variant, value));
447	      }
448	      for (const rule of definition.rules ?? []) {
449	        const issue = rulePresenceIssue(rule, value);
450	        if (issue) issues.push(issue);
451	      }
452	      return issues.length === 0 ? undefined : issues;
453	    },
454	    { title: 'FormDefinition.presence' },
455	  );
