461	/**
462	 * Compile a `FormDefinition` into the Effect Schema codec that validates its
463	 * submissions. The common `fields` and the optional variant fields form one
464	 * `Schema.Struct`; a SINGLE struct-level presence filter
465	 * ({@link makePresenceFilter}) re-imposes the variant's selected-branch
466	 * requirements and every cross-field rule, accumulating all issues at their own
467	 * field paths. The struct's `Issue` tree feeds `formatSchemaResult` unchanged.
468	 * One accumulating filter (not a chain of `.check`s) is required so multiple
469	 * unsatisfied requirements all surface, matching the oracle's single struct
470	 * filter.
471	 */
472	export const definitionToSchema = (
473	  definition: FormDefinition,
474	): Schema.Codec<DecodedForm, Encoded> => {
475	  const fields: Record<string, Schema.Top> = buildStructFields(
476	    definition.fields,
477	  );
478	  if (definition.variant) {
479	    Object.assign(fields, buildVariantOptionalFields(definition.variant));
480	  }
481	
482	  const struct = Schema.Struct(fields).check(
483	    makePresenceFilter(definition) as never,
484	  );
485	  return struct as unknown as Schema.Codec<DecodedForm, Encoded>;
486	};
