 37	const makeFormArgs = (fields: Record<string, string>): RouteArgs => {
 38	  const body = new URLSearchParams(fields);
 39	  const url = 'http://localhost/contact';
 40	  const request = new Request(url, {
 41	    method: 'POST',
 42	    body,
 43	    headers: { 'content-type': 'application/x-www-form-urlencoded' },
 44	  });
 45	  const context = new RouterContextProvider();
 46	  context.runtime = makeRequestRuntime();
 47	  return {
 48	    request,
 49	    url: new URL(url),
 50	    pattern: '/contact',
 51	    params: {},
 52	    context,
 53	  };
 54	};
