 56	describe('formAction', () => {
 57	  it('runs notify with the decoded payload, then redirects with the success toast', async () => {
 58	    let notified: DecodedForm | undefined;
 59	    const action = formAction({
 60	      form: 'contact',
 61	      notify: (decoded) =>
 62	        Effect.sync(() => {
 63	          notified = decoded;
 64	        }),
 65	      success: {
 66	        title: 'contact.form.success.title',
 67	        description: 'contact.form.success.description',
 68	      },
 69	    });
 70	
 71	    let thrown: unknown;
 72	    try {
 73	      await action(
 74	        makeFormArgs({
 75	          method: 'email',
 76	          name: 'Ada',
 77	          email: 'ada@example.com',
 78	          message: 'hi',
 79	        }),
 80	      );
 81	    } catch (error) {
 82	      thrown = error;
 83	    }
 84	
 85	    // The terminal toast.redirect fails with a RedirectError the runtime maps to
 86	    // a redirect Response (the C1 mapping the contact/volunteer actions rely on).
 87	    expect(thrown).toBeInstanceOf(Response);
 88	    const response = thrown as Response;
 89	    expect(response.status).toBe(302);
 90	    expect(response.headers.get('location')).toBe('/contact');
 91	    // The success toast was flashed (the set-cookie carries the toast session).
 92	    expect(response.headers.get('set-cookie')).toContain('toast');
 93	    // notify ran with the decoded payload.
 94	    expect(notified).toEqual({
 95	      method: 'email',
 96	      name: 'Ada',
 97	      email: 'ada@example.com',
 98	      message: 'hi',
 99	    });
100	  });
101	
102	  it('a notify failure aborts the redirect and reports a form-level error', async () => {
103	    const action = formAction({
104	      form: 'contact',
105	      notify: () =>
106	        Effect.fail(formValidationError({ formErrors: ['contact.form.error'] })),
107	      success: {
108	        title: 'contact.form.success.title',
109	        description: 'contact.form.success.description',
110	      },
111	    });
112	
113	    const result = await action(
114	      makeFormArgs({
115	        method: 'email',
116	        name: 'Ada',
117	        email: 'ada@example.com',
118	        message: 'hi',
119	      }),
120	    );
121	
122	    expect(result.status).toBe('error');
123	    expect(result.result.error?.formErrors).toEqual(['contact.form.error']);
124	  });
125	
126	  it('skips the body (no notify) when the honeypot is filled', async () => {
127	    let notifyRan = false;
128	    const action = formAction({
129	      form: 'contact',
130	      notify: () =>
131	        Effect.sync(() => {
132	          notifyRan = true;
133	        }),
134	      success: {
135	        title: 'contact.form.success.title',
136	        description: 'contact.form.success.description',
137	      },
138	    });
139	
140	    const result = await action(
141	      makeFormArgs({ name: 'Ada', website: 'https://spam.example' }),
142	    );
143	
144	    expect(notifyRan).toBe(false);
145	    expect(result.status).toBe('success');
146	  });
147	});

