102	      (value.method === "phone" || value.method === "both") &&
103	      value.phone === undefined
104	    ) {
105	      issues.push({ path: ["phone"], issue: "contact.form.phone.required" });
106	    }
107	    return issues.length === 0 ? undefined : issues;
108	  }),
