 14	/** Runtime type guard: is `schema` a Standard Schema V1 value? */
 15	function isStandardSchemaV1(schema: unknown): schema is StandardSchemaV1 {
 16	  if (schema === null || schema === undefined) return false;
 17	  const kind = typeof schema;
 18	  if (kind !== 'object' && kind !== 'function') return false;
 19	  const candidate = schema as { '~standard'?: { version?: unknown } };
 20	  return (
 21	    typeof candidate['~standard'] === 'object' &&
 22	    candidate['~standard'] !== null &&
 23	    candidate['~standard'].version === 1
 24	  );
 25	}
