 27	/**
 28	 * Serialize a Standard Schema issue path into a conform field name. Mirrors the
 29	 * server-side `formatSchemaResult`: object segments (`{ key }`) are unwrapped and
 30	 * numbers stay numeric so {@link formatPath} renders `registrants[0].email`
 31	 * rather than a dotted join that would never attach to the field.
 32	 */
 33	function issuePathToName(
 34	  path: ReadonlyArray<PropertyKey | StandardSchemaV1.PathSegment> | undefined,
 35	): string {
 36	  if (!path || path.length === 0) return '';
 37	  const segments: Array<string | number> = [];
 38	  for (const segment of path) {
 39	    const value =
 40	      typeof segment === 'object' && segment !== null && 'key' in segment
 41	        ? segment.key
 42	        : segment;
 43	    if (typeof value === 'string' || typeof value === 'number') {
 44	      segments.push(value);
 45	    }
 46	  }
 47	  return formatPath(segments);
 48	}
 49	
 50	/** Bucket Standard Schema issues into conform's `{ formErrors, fieldErrors }`. */
 51	function formatIssues(
 52	  issues: ReadonlyArray<StandardSchemaV1.Issue>,
 53	): FormError<string[]> {
 54	  const error: FormError<string[]> = { formErrors: null, fieldErrors: {} };
 55	  for (const issue of issues) {
 56	    const name = issuePathToName(issue.path);
 57	    if (name === '') {
 58	      (error.formErrors ??= []).push(issue.message);
 59	    } else {
 60	      (error.fieldErrors[name] ??= []).push(issue.message);
 61	    }
 62	  }
 63	  return error;
 64	}
