1024	+export const formAction = <E>(config: FormActionConfig<E>) =>
1025	+  routeFormAction(function* () {
1026	+    const { url } = yield* ReactRouterContext;
1027	+    const submission = yield* SubmissionContext;
1028	+    const content = yield* Content.Service;
1029	+    const toast = yield* Toast;
1030	+
1031	+    const definition = yield* content.getForm(config.form);
1032	+
1033	+    const decoded = decodeForm(definition, submission.payload);
1034	+    if (Result.isFailure(decoded)) {
