1040	+    yield* toast.redirect(url.pathname, {
1041	+      title: config.success.title,
1042	+      description: config.success.description,
1043	+      type: 'success',
1044	+      form: config.form,
1045	+    });
1046	+    return { reset: true } satisfies FormSuccess;
1047	+  });
